const expectedParagraphs = Number($node['Prepare Writer Payload'].json.expectedParagraphs || 0);
let rawContent = $items('Agent: Chapter Writer')[0].json.choices[0].message.content;
rawContent = rawContent.replace(/```json\n?|```/g, '').replace(/<think>[\\s\\S]*?<\/think>/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (e) {
  throw new Error('Invalid JSON from chapter writer: ' + rawContent);
}

const paragraphs = Array.isArray(parsed?.paragraphs) ? parsed.paragraphs : [];
if (!Array.isArray(paragraphs) || paragraphs.length === 0) {
  throw new Error('Chapter writer returned no paragraphs');
}

const normalized = paragraphs
  .map((paragraph) => ({
    paragraph_number: Number(paragraph?.paragraph_number),
    content: typeof paragraph?.content === 'string' ? paragraph.content.replace(/```markdown\n?|```/g, '').trim() : ''
  }))
  .filter((paragraph) => Number.isFinite(paragraph.paragraph_number) && paragraph.paragraph_number > 0 && paragraph.content.length > 0)
  .sort((a, b) => a.paragraph_number - b.paragraph_number);

if (expectedParagraphs > 0 && normalized.length !== expectedParagraphs) {
  throw new Error(`Chapter writer returned ${normalized.length} paragraphs, expected ${expectedParagraphs}`);
}

const uniqueNumbers = new Set(normalized.map((paragraph) => paragraph.paragraph_number));
if (uniqueNumbers.size !== normalized.length) {
  throw new Error('Chapter writer returned duplicate paragraph_number values');
}

return [{ json: { paragraphs: normalized } }];
